// Normalize Input
const triggerData = $('Execute Workflow Trigger').first().json || {};
const j = { ...triggerData, ...($json || {}) };

if (!j.userPrompt) throw new Error('userPrompt is required');

function sanitizePrompt(val) {
  if (val == null) return '';
  return String(val).replace(/\x00/g, '');
}

const llm_provider = (j.llm_provider || j.DEFAULT_PROVIDER || 'google').toLowerCase();

let model;
if (llm_provider === 'anthropic') {
  model = j.anthropic_model || j.DEFAULT_ANTHROPIC_MODEL || 'claude-haiku-4-5-20251001';
} else if (llm_provider === 'google') {
  model = j.google_model || j.DEFAULT_GOOGLE_MODEL || 'gemini-3.5-flash';
} else if (llm_provider === 'mistral') {
  model = j.mistral_model || j.DEFAULT_MISTRAL_MODEL || 'mistral-medium-latest';
} else if (llm_provider === 'openai') {
  model = j.openai_model || j.DEFAULT_OPENAI_MODEL || 'gpt-5.4-mini';
}

const temperature = typeof j.temperature === 'number'   ? j.temperature
                  : typeof j.temperature === 'string'   ? parseFloat(j.temperature) || 0.5
                  : typeof j.DEFAULT_TEMPERATURE === 'number' ? j.DEFAULT_TEMPERATURE
                  : 0.5;

const max_tokens = parseInt(j.max_tokens, 10)
  || parseInt(j.DEFAULT_MAX_TOKENS, 10)
  || 5000;

const response_format = j.response_format || j.DEFAULT_RESPONSE_FORMAT || 'json';
const systemPrompt    = sanitizePrompt(j.systemPrompt);
const userPrompt      = sanitizePrompt(j.userPrompt);

const isReasoningModel = llm_provider === 'openai' && /^o[0-9]/i.test(model);
const isNewOpenAI      = llm_provider === 'openai' && /^gpt-5/i.test(model);

const provider_body = {
  model,
  ...(!isReasoningModel && { temperature }),
  ...((isNewOpenAI || isReasoningModel) ? { max_completion_tokens: max_tokens } : { max_tokens }),
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user',   content: userPrompt }
  ]
};

return {
  json: {
    ...j,
    llm_provider,
    response_format,
    model_used:    model,
    provider_used: llm_provider,
    provider_body
  }
};

function estimateTokens(text, provider) {
  if (!text) return 0;
  const str = String(text);
  if (provider === 'openai' || provider === 'anthropic') {
    const words = str.trim() ? str.trim().split(/\s+/).length : 0;
    return Math.ceil(words * 1.3);
  } else if (provider === 'google') {
    return Math.ceil(str.length / 3.5);
  }
  return Math.ceil(str.length / 4);
}

const provider      = ($json.llm_provider || 'google').toLowerCase();
const systemContent = $json.provider_body?.messages?.[0]?.content || '';
const userContent   = $json.provider_body?.messages?.[1]?.content || '';

const systemTokens = estimateTokens(systemContent, provider);
const userTokens   = estimateTokens(userContent,   provider);
const totalInput   = systemTokens + userTokens;

const MODEL_LIMITS = {
  'claude-haiku-4-5-20251001':  200000,
  'claude-haiku-4-5':           200000,
  'claude-sonnet-4-6':         1000000,
  'claude-sonnet-4-5-20250929': 200000,
  'claude-sonnet-4-5':          200000,
  'claude-opus-4-8':           1000000,
  'claude-opus-4-7':           1000000,
  'claude-fable-5':            1000000,
  'gemini-3.5-flash':          1000000,
  'gemini-3-flash':            1000000,
  'gemini-2.5-flash':          1000000,
  'gemini-2.5-flash-lite':     1000000,
  'gpt-5.5':                   1000000,
  'gpt-5.4':                   1000000,
  'gpt-5.4-mini':               400000,
  'gpt-4o':                     128000,
  'gpt-4o-mini':                128000,
  'mistral-medium-latest':      128000,
  'mistral-small-latest':       128000,
  'mistral-large-latest':       128000,
};

const model = $json.provider_body?.model || '';
const limit = MODEL_LIMITS[model] || 32000;

if (totalInput > limit * 0.7) {
  throw new Error(
    `Prompt too large: ~${totalInput} estimated tokens (model limit: ${limit}). ` +
    `Reduce prompt length or switch to a larger model.`
  );
}

return { json: { ...$json, _token_estimate: totalInput } };

// Merge Provider Response
const idx  = typeof $itemIndex === 'number' ? $itemIndex : 0;
const orig = ($items('Validate Token Budget')?.[idx]?.json) || {};

const base = $json?.body ?? $json ?? {};

function extractContentFromJSON(str) {
  if (!str) return str;
  let clean = str.replace(/^```(json)?\n?/i, '').replace(/\n?```$/i, '').trim();
  try {
    const parsed = JSON.parse(clean);
    if (typeof parsed === 'object' && parsed !== null) {
      if (parsed.output)      return parsed.output;
      if (parsed.response)    return parsed.response;
      if (parsed.content)     return parsed.content;
      if (parsed.story)       return parsed.story;
      if (parsed.text)        return parsed.text;
      if (parsed.story_bible) return parsed.story_bible;
      return clean;
    }
    return clean;
  } catch (e) {
    clean = clean.replace(/(?<!:)(\s)"([a-zA-Z0-9])/g, '$1\\"$2');
    clean = clean.replace(/([a-zA-Z0-9\.?!])"(?![,\}\]:])/g, '$1\\"');
    return clean;
  }
}

let outputText   = '';
let rawErrorBody = '';

if (base.candidates?.[0]?.content?.parts?.[0]?.text) {
  outputText = base.candidates[0].content.parts[0].text;
}
else if (Array.isArray(base.content) && base.content[0]?.text) {
  outputText = base.content[0].text;
}
else if (base.choices?.[0]?.message?.content) {
  outputText = base.choices[0].message.content;
}
else if (base.text)                                        outputText = base.text;
else if (base.content && typeof base.content === 'string') outputText = base.content;
else if (base.message?.content)                            outputText = base.message.content;
else if (base.output)                                      outputText = base.output;
else if (base.error) {
  rawErrorBody = '[API ERROR] ' + JSON.stringify(base.error);
} else {
  const raw = JSON.stringify($json);
  if (raw && raw.length > 2) rawErrorBody = '[UNEXPECTED RESPONSE] ' + raw.substring(0, 300);
}

const trimmed         = outputText ? outputText.trim() : '';
const isJSON          = trimmed.startsWith('{') || trimmed.startsWith('[') || trimmed.includes('```json');
const callerWantsJson = (orig.response_format || '').toLowerCase().includes('json');

if (isJSON) {
  if (callerWantsJson) {
    outputText = trimmed.replace(/^```(json)?\n?/i, '').replace(/\n?```$/i, '').trim();
  } else {
    outputText = extractContentFromJSON(outputText);
  }
}

let _actual_input_tokens  = null;
let _actual_output_tokens = null;

if (base.usage) {
  if (typeof base.usage.input_tokens === 'number') {
    _actual_input_tokens  = base.usage.input_tokens;
    _actual_output_tokens = base.usage.output_tokens    ?? null;
  }
  else if (typeof base.usage.prompt_tokens === 'number') {
    _actual_input_tokens  = base.usage.prompt_tokens;
    _actual_output_tokens = base.usage.completion_tokens ?? null;
  }
}
else if (base.usageMetadata) {
  _actual_input_tokens  = base.usageMetadata.promptTokenCount      ?? null;
  _actual_output_tokens = base.usageMetadata.candidatesTokenCount  ?? null;
}

delete orig.provider_body;

return {
  json: {
    ...orig,
    llm_response:         outputText || rawErrorBody,
    _actual_input_tokens,
    _actual_output_tokens,
  }
};

const COSTS = {
  anthropic: {
    'claude-haiku-4-5-20251001':  { input: 0.001,    output: 0.005   },
    'claude-haiku-4-5':           { input: 0.001,    output: 0.005   },
    'claude-sonnet-4-6':          { input: 0.003,    output: 0.015   },
    'claude-sonnet-4-5-20250929': { input: 0.003,    output: 0.015   },
    'claude-sonnet-4-5':          { input: 0.003,    output: 0.015   },
    'claude-opus-4-8':            { input: 0.005,    output: 0.025   },
    'claude-opus-4-7':            { input: 0.005,    output: 0.025   },
    'claude-fable-5':             { input: 0.01,     output: 0.05    },
  },
  google: {
    'gemini-3.5-flash':           { input: 0.0003,   output: 0.0025  },
    'gemini-3-flash':             { input: 0.001,    output: 0.004   },
    'gemini-2.5-flash':           { input: 0.0003,   output: 0.0025  },
    'gemini-2.5-flash-lite':      { input: 0.0001,   output: 0.0004  },
  },
  openai: {
    'gpt-5.5':                    { input: 0.005,    output: 0.02    },
    'gpt-5.4':                    { input: 0.005,    output: 0.02    },
    'gpt-5.4-mini':               { input: 0.0003,   output: 0.0012  },
    'gpt-4o':                     { input: 0.0025,   output: 0.01    },
    'gpt-4o-mini':                { input: 0.00015,  output: 0.0006  },
  },
  mistral: {
    'mistral-medium-latest':      { input: 0.0004,   output: 0.002   },
    'mistral-small-latest':       { input: 0.0001,   output: 0.0003  },
    'mistral-large-latest':       { input: 0.002,    output: 0.006   },
  },
};

const provider    = $json.provider_used || '';
const model       = $json.model_used    || '';
const llmResponse = $json.llm_response  || '';

const inputTokens  = $json._actual_input_tokens
  ?? ($json._token_estimate || 0);
const outputTokens = $json._actual_output_tokens
  ?? Math.ceil(llmResponse.length / 4);

const rates = COSTS[provider]?.[model];
const estimatedCostUsd = rates
  ? (inputTokens / 1000) * rates.input + (outputTokens / 1000) * rates.output
  : null;

return {
  json: {
    ...$json,
    llm_response_length: llmResponse.length,
    llm_response_empty:  llmResponse.length === 0,
    _input_tokens:       inputTokens,
    _output_tokens:      outputTokens,
    _estimated_cost_usd: estimatedCostUsd,
  }
};

const idx = typeof $itemIndex === 'number' ? $itemIndex : 0;
const orig = ($items('Execute Workflow Trigger')?.[idx]?.json) || {};

return { json: { ...orig, ...$json } };
